import './CategorywiseExpenseChart.css';
import {
    PieChart,
    Pie,
    Tooltip,
    Legend,
    ResponsiveContainer
} from "recharts";

function CategorywiseExpenseChart({categoryData}) {
    const pieChartData = Object.entries(categoryData).map(
        ([category, amount]) => ({
            category,
            amount
        })
    );
}
export default CategorywiseExpenseChart;
